import React, { useState, useMemo, useCallback } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import { createAccountSearchConfig } from '../../../components/search';
import { SearchInput } from '@linm-soft/common-components';
import { reportPageLabels } from '../../../constants/reportPageLabels';
import { formatDateLocal, formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import { MONTH_OPTIONS, yearOptions } from '../../../constants/voucher';

import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const labels = reportPageLabels.soChiTiet;

const SoChiTietPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [accountCode, setAccountCode] = useState('');
  const [rows, setRows] = useState<Record<string, unknown>[]>([]);
  const [loading, setLoading] = useState(false);
  const accountSearchConfig = useMemo(() => createAccountSearchConfig(), []);

  const fromDate = `${year}-${month.padStart(2, '0')}-01`;
  const lastDay = new Date(Number(year), Number(month), 0).getDate();
  const toDate = `${year}-${month.padStart(2, '0')}-${lastDay}`;

  const handleLoad = useCallback(async () => {
    if (!accountCode) {
      dispatch(addToast({ message: labels.selectAccount, type: 'error' }));
      return;
    }
    setLoading(true);
    try {
      const data = await ktService.getAccountDetailLedger({ accountCode, fromDate, toDate });
      const list = (data as { lines?: Record<string, unknown>[] })?.lines ?? (Array.isArray(data) ? data : []);
      setRows(list as Record<string, unknown>[]);
    } catch (e: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(e, labels.loadError), type: 'error' }));
    } finally {
      setLoading(false);
    }
  }, [accountCode, fromDate, toDate, dispatch]);

  return (
    <div className={erp.page}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-list-alt" /> {labels.title}</h1></div>
      </div>
      <div className={erp.filtersBar} data-testid={`erp-so-chi-tiet-filters`}>
        <Select value={month} onChange={e => setMonth(e.target.value)} options={MONTH_OPTIONS} />
        <Select value={year} onChange={e => setYear(e.target.value)} options={yearOptions()} />
        <SearchInput config={accountSearchConfig} value={accountCode} primaryDisplay={accountCode}
          onChange={a => setAccountCode(a.code)} onClear={() => setAccountCode('')} showSecondaryInput={false} placeholder={labels.accountPlaceholder} />
        <Button variant="primary" onClick={handleLoad} loading={loading}>{labels.view}</Button>
        <ListSearchRefreshButtons testIdPrefix="erp-so-chi-tiet" onSearch={handleLoad} onRefresh={handleLoad} showSearch={false} />
      </div>
      <div className={erp.tableCard}>
        {rows.length === 0 ? <div className={erp.empty}>{labels.empty}</div> : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead><tr><th>{labels.colDate}</th><th>{labels.colVoucher}</th><th>{labels.colDescription}</th><th className={erp.colRight}>{labels.colDebit}</th><th className={erp.colRight}>{labels.colCredit}</th></tr></thead>
              <tbody>{rows.map((r, i) => (
                <tr key={i}>
                  <td>{formatDateLocal(String(r.entryDate ?? ''))}</td>
                  <td><code>{String(r.voucherCode ?? '')}</code></td>
                  <td>{String(r.description ?? '')}</td>
                  <td className={erp.colRight}>{formatVnd(Number(r.debitAmount ?? 0))}</td>
                  <td className={erp.colRight}>{formatVnd(Number(r.creditAmount ?? 0))}</td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default SoChiTietPage;
